    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, storageKey, content);
    }

    public async ValueTask<string?> LoadAsync(string storageKey)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string?>(LoadMethod, storageKey);
    }

    public async ValueTask ClearAsync(string storageKey)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod, storageKey);
    }

    public async ValueTask SetDirtyAsync(bool isDirty)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SetDirtyMethod, isDirty);
    }

    public async ValueTask DisposeAsync()
    {
        try
