                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

let onBeforeUnload = null;

export function initialize(storageKey) {
    // Register beforeunload only once; setDirty controls whether it fires.
    onBeforeUnload = (e) => {
        e.preventDefault();
    };
}

export function save(storageKey, content) {
    localStorage.setItem(storageKey, content);
}

export function load(storageKey) {
    return localStorage.getItem(storageKey);
}

export function clear(storageKey) {
    localStorage.removeItem(storageKey);
}

export function setDirty(isDirty) {
    if (isDirty) {
        window.addEventListener("beforeunload", onBeforeUnload);
    } else {
        window.removeEventListener("beforeunload", onBeforeUnload);
    }
}

