@page "/notepad"
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea @bind="Content" @bind:event="oninput" rows="12" class="form-control mb-3"
          placeholder="Type your notes here…"></textarea>

<div class="d-flex align-items-center gap-2 mb-2">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSaved is not null)
    {
        <span class="text-muted">Last saved at @_lastSaved.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private const string StorageKey = "notepad-content";

    private string Content
    {
        get => _content;
        set
        {
            if (_content != value)
            {
                _content = value;
                _isDirty = true;
            }
        }
    }

    private string _content = string.Empty;
    private string _savedSnapshot = string.Empty;
    private bool _isDirty;
    private DateTime? _lastSaved;
    private NotepadInterop? _interop;
    private Timer? _autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            await _interop.InitializeAsync(StorageKey);

            var saved = await _interop.LoadAsync(StorageKey);
            if (!string.IsNullOrEmpty(saved))
            {
                _content = saved;
                _savedSnapshot = saved;
                StateHasChanged();
            }

            _autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        await InvokeAsync(async () =>
        {
            await PerformSaveAsync();
            StateHasChanged();
        });
    }

    private async Task SaveNowAsync()
    {
        await PerformSaveAsync();
    }

    private async Task PerformSaveAsync()
    {
        if (_interop is null) return;

        await _interop.SaveAsync(StorageKey, _content);
        _savedSnapshot = _content;
        _isDirty = false;
        _lastSaved = DateTime.Now;
        await _interop.SetDirtyAsync(false);
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;

        _content = string.Empty;
        _savedSnapshot = string.Empty;
        _isDirty = false;
        _lastSaved = null;
        await _interop.ClearAsync(StorageKey);
        await _interop.SetDirtyAsync(false);
    }

    protected override async Task OnParametersSetAsync()
    {
        // Update the beforeunload guard whenever dirty state may have changed.
        if (_interop is not null && _isDirty && _content != _savedSnapshot)
        {
            await _interop.SetDirtyAsync(true);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_autoSaveTimer is not null)
        {
            await _autoSaveTimer.DisposeAsync();
        }

        if (_interop is not null)
        {
            await _interop.DisposeAsync();
        }
    }
}

